#include <queue>
#include <vector>

using namespace std;

/**
 * Stock Trading Maximum Profit - Regret-Based Greedy Algorithm
 * 
 * Problem: Buy and sell stocks over n days with transaction fee C per sale.
 * At most one share can be traded per day. Find maximum profit.
 * 
 * Algorithm:
 * - Use a min-heap to maintain all potential buy costs
 * - For each day's price, check if we can profit by selling (price - C > min_buy_cost)
 * - When selling, push back two values to support "regret" operations:
 *   1. price - allows undoing this sale if a higher price appears later
 *   2. price - C - represents effective cost for potential future transactions
 * 
 * Time Complexity: O(n log n)
 * Space Complexity: O(n)
 */

int main() {
    // Optimize I/O operations
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    long long C;

    if (!(cin >> n >> C)) {
        return 0;
    }

    // Min-heap to store potential buy costs
    // Using greater<long long> for min-heap behavior
    priority_queue<long long, vector<long long>, greater<long long>> pq;

    long long maxProfit = 0;

    for (int i = 0; i < n; i++) {
        long long price;
        cin >> price;

        // Check if we can make a profit by selling at current price
        // Profit = price - buy_cost - C
        // We sell if price - C > buy_cost (i.e., price - C > pq.top())
        if (!pq.empty() && price - C > pq.top()) {
            long long buyCost = pq.top();
            pq.pop();

            // Execute the transaction: profit += price - buyCost - C
            maxProfit += price - buyCost - C;

            // Push back for regret operations:
            // 1. Push 'price' - allows us to "regret" this sale later
            //    If we find a higher price later, we can effectively change
            //    our sale from 'price' to the higher price
            // 2. Push 'price - C' - represents the net proceeds after fee,
            //    which can be used as a buy cost for future transactions
            pq.push(price);
            pq.push(price - C);
        } else {
            // No profitable sale, consider this as a potential buy point
            pq.push(price);
        }
    }

    cout << maxProfit << endl;

    return 0;
}"}

